INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('d91de51d-69b5-4e41-a00e-993782ee3274', '93f4395e-82ed-4881-8737-003f80cb34bb', 0, 0, '<div class="text js_memo_node" style="width: 680px; font-size: 15px; line-height: 22px; overflow-wrap: break-word; word-break: break-all; color: rgb(51, 51, 51); overflow: hidden; position: relative; zoom: 1; font-family: arial, tahoma, sans-serif;"><p class="first" style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">11月26日，晴</p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">下午2：00左右到达龙门古镇，古镇全是石头仔儿路，无法拉行李，只好费力地挎着，好在只有200多米就到了我预订的墨庄民宿。200一晚，旧房改造的，房间一点点大。我出行非常不喜欢民宿，价格高，条件差，比连锁经济酒店差太远了。但龙门古镇同样没有酒店，墨庄酒店在订房网上叫酒店，实际还是民宿。但床上用品还挺干净，一客一换没问题，赶紧洗了个澡才舒服些。</p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;"></p></div><dl class="js_memo_node" style="margin: 25px 0px 0px; padding: 0px; zoom: 1; min-width: 134px; color: rgb(85, 85, 85); font-family: arial, tahoma, sans-serif; font-size: 12px;"><dt class="cur" style="width: 680px; position: relative; top: 0px; left: 0px; display: inline-block; font-size: 0px; zoom: 1; min-width: 144px; min-height: 95px; background-color: rgb(248, 248, 248);"><img data-idx="1" data-id="176973665" title="龙门古镇图片" alt="龙门古镇图片" width="680px" height="509px" data-original="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_01710e1a152f21b48baf76ec8e3ce6c5.jpg_r_680x509x95_c553861f.jpg" data-retina="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_01710e1a152f21b48baf76ec8e3ce6c5.jpg_r_1360x1360x95_65837c79.jpg" class="box_img js_box_img js_lazyimg" src="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_01710e1a152f21b48baf76ec8e3ce6c5.jpg_r_1360x1360x95_65837c79.jpg" style="border: 0px; cursor: pointer; display: inline;"></dt></dl><dl class="js_memo_node" style="margin: 25px 0px 0px; padding: 0px; zoom: 1; min-width: 134px; color: rgb(85, 85, 85); font-family: arial, tahoma, sans-serif; font-size: 12px;"><dt class="" style="width: 525px; position: relative; top: 0px; left: 0px; display: inline-block; font-size: 0px; zoom: 1; min-width: 144px; min-height: 95px; background-color: rgb(248, 248, 248);"><img data-idx="2" data-id="176988184" title="龙门古镇图片" alt="龙门古镇图片" width="525px" height="680px" data-original="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_94899b27195161faf33a68f139dc983e.jpeg_r_525x680x95_d4644a68.jpeg" data-retina="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_94899b27195161faf33a68f139dc983e.jpeg_r_1360x1360x95_609bafef.jpeg" class="box_img js_box_img js_lazyimg" src="https://tr-osdcp.qunarzz.com/tr_osd_tr_hy/tr-osd-tr-space-img_94899b27195161faf33a68f139dc983e.jpeg_r_1360x1360x95_609bafef.jpeg" style="border: 0px; cursor: pointer; display: inline;"></dt></dl><div class="text js_memo_node" style="width: 680px; font-size: 15px; line-height: 22px; overflow-wrap: break-word; word-break: break-all; color: rgb(51, 51, 51); overflow: hidden; position: relative; zoom: 1; font-family: arial, tahoma, sans-serif;"><p class="first" style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;"></p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">龙门古镇位于‌杭州富阳区，是三国东吴大帝‌孙权后裔的最大聚居地，以保存完好的明清古建筑群和宗族文化为核心特色。现在住的基本都是原住民，烟火气息浓郁，是现今江南地区明清古建筑群中保存较为完整的山乡田园古镇。</p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">古镇以两座孙氏宗祠为中心，现存40余座厅堂、3座牌楼及古塔寺庙，形成迷宫式街巷布局。</p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">龙门古镇还是《富春山居图》的作画地，很多影视剧的取景地，陈逸飞导演的《理发师》，《富春山居图》，《租个女友回家》这些电影都是在龙门拍的。看看，虽然名气好像不大，但的确不同凡响。孙权故里的遗风藏在斑驳的墙垣间，一砖一瓦都写满了岁月的故事。</p><p style="margin: 10px 0px 0px; padding: 0px; line-height: 26px; font-size: 14px; min-height: 20px;">休息到3：00才出门，先找吃的，古镇有著名的龙门面筋，是用小麦粉多次洗淘后作为皮儿，再包上肉竹笋馅子进油锅炸成的，非常好吃。出门就进了对面一家小店，要了一个煎饼、一碗小馄饨，2个面筋，都很好吃。</p></div>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('7890dc52-6228-4ce5-b38b-5979a4f05522', '1d9274a2-82fe-41f2-8964-3fa5b795f137', 0, 0, '1111111', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('e32caccc-d97e-4156-b9ad-f33b172c57ab', '980ac9f9-5cbb-49d8-a754-313f895d4024', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">镇江金山寺，这是一个富有传奇色彩的地方，相传陆羽在这里喝过茶，玄奘在这里长大，李白在这里醉酒当歌，岳飞来这里寻访故友，康熙爷在此留下墨宝，乾隆爷在这里找过亲爹，最让老百姓津津乐道的是《白蛇传》，话说法海拆散白娘子和许仙这对CP后，把许仙困在金山寺中，后来白娘子怒不可遏引钱塘江水怒淹法海所在的金山寺，跟法海各放大招，上演了水漫金山的僧妖对决。千百年来老百姓似乎对这位棒打鸳鸯的法海和尚，并无好感，《法海不懂爱》的神曲更是朗朗上口，那么在金山寺，是否真有法海这样一位和尚呢？</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🧑🏻‍💻法海本尊：金山寺法海禅师，历史上确有其人，金山寺有法海洞，就是法海当年坐禅修行的地方。法海是唐代人，曾是当朝宰相的儿子，更是位正经的得道高僧，《白蛇传》是民间故事，再说了这白娘子用浙江</span><a target="_blank" href="https://bbs.youxiake.com/mdd/16.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">杭州</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">钱塘江的水，去淹</span><a target="_blank" href="https://bbs.youxiake.com/mdd/77.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">江苏</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">镇江的金山寺，这……</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🏯关于金山寺：不得不说《白蛇传》里的法海，成就了金山寺，这是镇江旅行必到的一个景点，它始建于东晋，唐朝的时候叫金山寺，宋朝叫龙游寺，清朝叫江天禅寺，但老百姓只认金山寺的叫法</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">💡金山寺看点：山门的牌匾上“江天禅寺”四字为清康熙皇帝御笔；金山之巅的留云亭内有康熙“认证”的“江天一揽”四个大字；慈寿塔，跟慈禧老佛爷有些渊源；“四大名洞”除法海洞外，还有白龙洞、朝阳洞和仙人洞</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('5bd92bf3-e0d5-4b98-8c10-21849d11d8de', '4ac50c44-776b-4a9b-b84a-c9bad31215e3', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">西津渡位于</span><a target="_blank" href="https://bbs.youxiake.com/mdd/77.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">江苏</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">省镇江市城区</span><a target="_blank" href="https://bbs.youxiake.com/mdd/3.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">西北</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">部云台山麓，是国家&nbsp;AAAA&nbsp;级旅游景区&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">历史渊源</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;形成时间：西津渡始成于三国时期，距今约1400年历史&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;重要发展阶段：自唐代起具有完备的渡口功能，一直是我国南北水上交通、漕运枢纽&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;相关历史事件：东晋隆安五年，农民起义军领袖孙恩曾控制西津渡口；宋熙宁元年，王安石从西津渡扬舟北去写下《泊船瓜洲》；清代后期，长江江岸北移，渡口功能逐渐淡化&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">文化特色</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;津渡文化：作为古代重要渡口，见证无数船只往来、人员穿梭，是南北交通咽喉&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;宗教文化：古街有观音洞、昭关石塔等宗教遗迹，反映当时宗教兴盛及对民众生活影响&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;民居文化：古街上建筑多为明清遗迹，砖木结构，飞檐雕花窗栏，呈现江南传统民居特色&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">主要景点</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;镇江博物馆：馆内珍藏不同时代文物&nbsp;3&nbsp;万余件套，如西周鸳鸯尊等&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;五十三坡：佛教典籍相关的劝善故事场景&nbsp;。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">•&nbsp;救生会：始建于康熙三十一年，是带有慈善性质的水上安全救助机构&nbsp;。</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('295f413c-cf9b-48fd-b37a-03bb290e0826', 'af429401-afbd-4712-9920-bc99e3f5d0b5', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">京口瓜洲一水间，钟山只隔数重山。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">春风又绿江南岸，明月何时照我还。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">宋熙宁元年&nbsp;(1008)&nbsp;春，王安石应召赴京，从西津渡扬舟北去，舟次瓜洲时，即景抒情，写下了著名的《泊船瓜洲》。</span><div><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">西津渡古街全长约&nbsp;1000&nbsp;米&nbsp;，始创于六朝时期，历经唐宋元明清五个朝代的建设，留下了如今的规模，因此，整条街随处可见六朝至清代的历史踪迹。西津渡，三国时叫“蒜山渡”，唐代曾名“金陵渡”，宋代以后才称为“西津渡”。这里原先紧临长江，滚滚江水就从脚下流过。清代以后，由于江滩淤涨，江岸逐渐北移，渡口遂下移到玉山脚下的超岸寺旁。当年的西津古渡现在离长江江岸已有&nbsp;300&nbsp;多米距离。</span><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"></span></div><div><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">古街道两边的建筑大多数是元明清时期的风格，街道沿山势起伏，中为石板路，徜徉其间，让人感慨万千。</span><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"></span></div>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('8c189088-82a3-4db4-99b3-ac30c8f8c9b1', '42ec7c81-6d54-4ec6-9fa0-4918d132572c', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这座城市，山中有城，城中有山，滚滚江水奔涌而下。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">千百年前的诗词传说沿颂至今，不绝于耳。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这里有三国纷争，兵家胜败。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">也有白蛇传奇，相守千年。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">渔歌唱晚，古刹钟鸣。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">每一个旅人的足迹都被印刻在城市的记忆齿轮之中，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">经过他，感知他，倾听他。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这里有别离，这里有相遇。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这里的故事关于你我。</span><div><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">初遇镇江，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">作为一个吃货首先映入脑海的可能是众多五味杂陈的味道；</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">肴肉的鲜香嫩滑，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">陈醋的酸醇浓香，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">锅盖面的喷香劲道。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">童年时期，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">每逢新年来镇江走亲戚的记忆就被这些食味香气串联起来，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">对小小的我而言，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这大概是一个能被称作好吃的城市吧。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">于是，记忆的味道成为了我们开启了此次西津渡+圌山之行的引子。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">在前往镇江的路途上，老游侠和新游侠除了做了常规的自我介绍以外。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">丹裕哥哥还抛出一道非常规采访“在你的家乡，最留恋的儿时味道是什么？”</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">呐~&nbsp;一道浓烈的乡味问答。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">“作为一个老</span><a target="_blank" href="https://bbs.youxiake.com/mdd/63.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">南京</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">，我印象最深的食物是年轻时候在部队大院上班，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">那时候晚饭点去街角花两块钱买的荷叶包猪头肉，那叫一个香呀~</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">跟现在街头巷尾的卤味店比起来，好吃的不是一星半点。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">几个大小伙子还没走回单位，肉就吃完了！哈哈哈哈~”.</span><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"></span></div>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('dc9fd2e1-695c-40a4-8104-b2f1f064bfef', '0a44ebb2-8fcb-41cc-9150-8dd9d2181784', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">✅07:15&nbsp;准时发车，整队出发！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">大家都非常守时，全部准时到达集合点，顺利登车出发～虽然途中遇上节假日高峰堵车，但整体旅程有序推进，大家的好心情丝毫没被影响！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🍃13:30&nbsp;抵达【茅山森林世界公园】</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">穿越堵车的考验，终于来到这片如梦似幻的森林秘境&nbsp;🌳。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">这里有：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">连绵竹海、森林精灵</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">童话山海茶田</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">萌宠世界与神奇魔法森林</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">仿佛走入了霍格沃兹的魔法学院，宝贝们跟着粑粑麻麻梦游“爱丽丝仙境”，开启奇妙的探险旅程！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🎠13:30-17:00&nbsp;魔法森林大冒险</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🌿青青大草原撒欢时光：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">宝贝们奔跑在绿茵草地，体验各种挑战项目：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🌈&nbsp;彩虹滑草</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🐒&nbsp;“人猿泰山”丛林挑战塔</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🚗&nbsp;儿童赛车</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🌳&nbsp;丛林树网</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">挑战满分，笑声不断！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🌫️闯入魔法黑森林：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">宝贝们手持魔杖穿越魔法书之门，走进一个如梦似幻的时空：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">空中漂浮的飞天巨鲸&nbsp;🐋</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">神出鬼没的柴郡猫&nbsp;🐱</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">还有可能遇到一位脾气火爆的女巫！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🦌林深见鹿秘境：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">森林深处藏着一群“会撒娇”的萌宠梅花鹿&nbsp;🦌～宝贝们亲手喂食，零距离邂逅小精灵，幸福值爆表！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🎉亲子大狂欢自由玩耍：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">如果时间充裕，可自由探索：</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🐏&nbsp;萌宠乐园（羊驼、仓鼠、孔雀等）</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🏹&nbsp;射箭体验</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🚗&nbsp;迷你赛车场</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">一个下午，满满的亲子互动时光！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">🍽️17:00-18:00&nbsp;美味晚餐时间</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">经过一下午的欢笑与奔跑，宝贝们终于可以大快朵颐，补充能量！</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('1952652f-57b7-4e8b-bf7c-750cb77eb448', 'e8bc5a6f-a688-4a27-9990-6a15be00c06a', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">镇江南山，秋意浓。漫步在这片“城市山林”中，感受秋的诗情画意。金黄的银杏叶与火红的枫叶交织，绘出一幅斑斓的秋日画卷。在这里，每一步都是风景，每一眼都是画。南山的秋天，是壮美、辽阔，充满希望的。历代文人墨客在此留连忘返，留下了珍贵的古迹和名篇。秋高气爽，正是登高望远的好时节，不妨来镇江南山，感受这份宁静与美好。</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('39573aed-944a-44e1-8398-b808d9133f5b', 'ac1cf947-6d8b-48a6-897a-e88818816f00', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">九连尖，徒步者的挑战地。山峦叠嶂，风光旖旎，每一步都是对自我的超越。呼吸着清新的空气，感受着自然的韵律，让心灵在山间小道上自由飞翔。九连尖，不仅是一场徒步，更是一次心灵的洗礼。挑战自我，享受自然，让我们在这片绿色中找到内心的宁静。</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('7e28d8dc-1d1d-4d2d-8494-c143782f43c3', 'e21fa629-5ab9-441f-9965-a27610740604', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">当你没有期待，反而为如何顺利完成带团而担心时，或许意外惊喜就会突然来敲门，比如高骊山偶遇的雾凇，比如返程的高速移动的欢快KTV，比如有幸遇到一群有趣可爱的队员们。。。。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">一开始就关注天气，会不会下雨，下多大，气温怎样，线路会不会取消，雨后山脊线难不难走。。。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">万幸，线路没有取消，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">所幸，当天徒步没有雨，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">有幸，遇到其他线路取消随机报过来的大佬，</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">庆幸，山脊线偶遇雾凇。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">一再提醒大家不要迟到，最终我们27+3的精品小团开启了高骊山征途，不能说是重走新四军当年抗战之路，但在韦岗战斗胜利纪念碑前带着大家热身拍集体照，仍然能感受到骨子里民族的热血在沸腾，历史是用来铭记的，可以更加清晰的照亮未来之路！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">我们一路前行，手脚并用攀爬，小心翼翼又哆哆嗦嗦，风越来越大，气温也越来越低，前几天降雨形成的雾气湿气慢慢状态下冰雪，挂在树上成了锋利的羽毛，慢慢演变成一簇簇雾凇，而我们就在雾凇下面的林子里尽情的撒欢，大部分山脊线可以手脚并用，并不危险。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">遇到比较危险路段，还是会停下来挨个帮身边的队员保驾护航，也会巧妙构图帮队员构图，借位拍一下大片，让他们觉得不虚此行。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">最后带着先头部队体验了一下疾速，后面平缓下坡地带，一路带着大家小跑下山，只为吃一楼热乎的招牌锅盖面。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">返程前，依旧按照惯例带领大家做拉伸，每次都会耐心的做三个八拍，不辞辛苦乐在其中，希望我们有生之年还能一起继续徒步，让身体和灵魂一直在路上。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">返程中，贡献了蚂蚁领队送给我他收集的一些有趣好玩的徽章，我也送给了喜欢收集徽章的队员，毕竟对于他们来说，拥有一枚新徽章有种如获至宝的感觉。邀请了几个小伙伴讲一下行程感受，雾凇确实是意料之外的惊喜。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">此次过来做上帝的波波领队更是带动全车气氛，大家点歌他来唱，也激起了大家的欲望，歌曲一首接一首，最后大巴师傅开玩笑的说，带我们多开一个小时让我们唱个够😂，一首《海阔天空》直戳泪点，想起读书时候，八块一盒盗版磁带最喜欢的就是beyond。也有队员读懂了我的心，带来了许嵩欢快的歌曲，感谢可爱的你们，遇到你们，是我的荣幸！末尾奉上金曲。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">此次高骊山，本来没有期待，更多的是担心，但我坚信，终将深深印刻在我的徒步生涯中。</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('64fd8e70-4918-4bf7-a613-fda06d739f0e', 'c78c23c8-2db0-4c92-be56-deca820e86a1', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">930一行16个人7：15出发，高架一开始飞驰前行，没想到到了中断又是堵车又是风雨，到达我们目的地镇江休博园已经接近下午2点了，正好是马戏表演，所以带着小宝贝们去看了一场久违的马戏表演。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">2个小时的游园时间在国庆长龙的人海中显得有些苍白，但是孩子们玩得特别开心。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">晚上有一半的客人选择去泡圌山温泉，回来的感受是，舒服的可以至少安排半天，所以听说有些客人回</span><a target="_blank" href="https://bbs.youxiake.com/mdd/86.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">上海</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">还约着朋友再去泡汤，可见泡汤的魅力！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">第二天，一早我们就带着朋友们8点在露营房车基地后面进行爬著名的圌山，有位4岁的小朋友全程自行爬完，让大朋友们都惊叹不已。1030出发去了西津渡，小宝贝们边完成任务边玩，也在任务中学到了关于西津渡的历史文化知识，也尝到了心心念念的锅盖面。下午2点来到了最后一站的镇江醋博物馆，在讲解员的带领下，大家听镇江香醋的前世今生听得有兹有味的，最后还每个人拿到了属于自己的特制醋，兴奋不已！</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">虽然旅程是短暂而紧凑的，但是看到小朋友开心的笑脸，一切都是值得的！</span>', NULL);
INSERT INTO [PostBlocks] ([Id], [PostId], [Order], [Type], [Content], [Caption]) VALUES ('197154e1-79a7-4c60-bf9a-cec31e7b74b5', 'ba17f2eb-9a9a-484e-add7-0a6ee00f3b87', 0, 0, '<span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">镇江曾是三国时东吴的首府，有很多历史遗迹和风景，留下历代很多骚人墨客的踪迹和文墨，是去江南不可绕开的地方。镇江长江边上的“三山”金山、焦山、北固山久负盛名，其中北固山更是三国时的名山。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;烟花三月，我们游览了山上的主要历史古迹。</span><br style="margin: 0px; padding: 0px; color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;走进石坊大门，就见一座剑拔弩张的雕像，称为“试剑石”。据说两位手持佩剑的人物分别是孙权、刘备。相传刘备来甘露寺相亲，与孙权二人游山时，各怀心思，暗中祷告，以佩剑劈石问天。果然剑落石开，各遂其愿，终成霸业。</span><div><font color="#666666" face="Microsoft YaHei"><br></font><div><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">我们直接登到了后峰西侧平台，“数帆亭”就座落在平台上，古时坐在亭中可观江中过往帆船，故取此名。而现在江流改道，帆船罕见，自然是数不到了。亭柱上有一幅对联：“千里江潮，不及弦歌声浩荡；满园花木，郁为梁栋气笼葱”。作者为清人罗志让，字耦廉，</span><a target="_blank" href="https://bbs.youxiake.com/mdd/77.html" style="margin: 0px; padding: 0px; color: rgb(51, 51, 51); font-family: &quot;Microsoft YaHei&quot;;">江苏</a><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;">丹徒人。</span><span style="color: rgb(102, 102, 102); font-family: &quot;Microsoft YaHei&quot;;"></span></div></div>', NULL);
