INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('14e0b838-a464-4b21-a7f8-293942c7abc2', '江苏省镇江市润州区西津渡街25号', NULL, 0.0, NULL, 'b15dcb1e-3a73-4e5d-ad87-3c0560e85154', '2026-03-12 06:01:39.5297555', NULL, '西津渡也称为西津渡历史文化街区，位于镇江市区西北，从金山公园往东步行十五分钟就能到。这里有一片历史气息浓郁的老房子，著名的西津渡古街就坐落于此。西津渡自三国时期便是渡口码头，后因江岸逐渐北移，渡口早已不在，只留下了西津渡古街搁在云台山的山腰上。', 'Attraction', NULL, NULL, NULL, 32.22088878097721, 119.43664580282537, '西津渡', '09:00 - 17:00', NULL, NULL, NULL, NULL, NULL, '人文历史, 古镇古村，停车方便, 公交可达', '免费', '2026-03-24 12:30:50.1714112', NULL);
