INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('8aab6918-402b-40f6-a55f-4c97ae5c2f89', '江苏省镇江市润州区伯先路85号', NULL, 5.0, NULL, '74efddd6-b9d2-43b4-84cd-904553e5b0e2', '2026-03-24 11:33:11.5585089', NULL, '镇江博物馆是一座地方历史综合艺术博物馆，是国家AAAA级风景旅游区。镇江博物馆西依云台山麓，北邻浩荡长江，东毗西津渡古街，是英国在中国沿海沿江建造得最早的领事馆之一，共5幢，建筑风格为东印度式。', 'Attraction', NULL, NULL, NULL, 32.21926099914085, 119.4385658410224, '镇江博物馆', '09:00 - 17:00', NULL, NULL, NULL, NULL, NULL, '人文历史，红色旅游，研学,文化展馆，停车方便, 公交可达，导览讲解', '免费', '2026-03-24 12:28:46.1658846', NULL);
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('f52316e0-3334-4398-90d9-0109e299b36d', '江苏省镇江市句容市宝华镇', NULL, 5.0, NULL, 'b725a5a2-b9eb-4339-92e2-abc0350fa3b6', '2026-03-24 11:38:26.3717722', NULL, '宝华山原名花山，因春天黄花漫山而得名，后因南北朝梁代高僧宝志来此结庵讲经，遂易名宝华山。宝华山森林公园素有“林麓之美，峰峦之秀，洞壑之深，烟霞之胜”四大奇景。', 'Attraction', NULL, NULL, NULL, 32.15057840002906, 119.04958078061678, '宝华山国家森林公园', '08:00 - 21:00', NULL, NULL, NULL, NULL, NULL, '四季皆宜,停车方便, 公交可达,自然风光,山水', '50元', '2026-03-24 12:27:37.4018978', NULL);
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('a3a22200-a61f-4173-98b1-bb066fef7556', '江苏省镇江市润州区金山路62号', NULL, 5.0, NULL, '444d5059-fab7-4ba7-b11e-e19bd41d571a', '2026-03-24 11:41:06.390827', NULL, '依山就势，使山与寺融为一体。寺内主要建筑为天王殿、大雄宝殿、观音阁、藏经楼、方丈室等。它自创建以来，经历代修葺，古迹甚多', 'Attraction', NULL, NULL, NULL, 32.21984368961663, 119.42145896004313, '金山寺', '08:00 - 17:00', NULL, NULL, NULL, NULL, NULL, '四季皆宜,人文历史,停车方便, 公交可达', '50元', '2026-03-24 12:26:51.122549', NULL);
