INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('2592b7bf-996c-4e4a-bece-01105e822df2', '江苏省镇江市京口区中山东路301号苏宁广场A座26层', NULL, 5.0, NULL, 'f359da93-1dc8-4da4-8053-5f963744803a', '2026-03-24 11:50:17.5060138', NULL, '镇江泡泡夜景酒店式公寓在镇江繁华的大市口商业中心位置，入驻镇江76层地标建筑苏宁广场A座。风格多样的房间给您多样的选择，给您家一样的温馨。周边交通方便，餐饮丰富，是您出差、旅游的理想选择', 'Accommodation', NULL, NULL, NULL, 32.20989420961556, 119.45946914074793, '镇江泡泡夜景酒店式公寓', NULL, NULL, NULL, NULL, NULL, 3, '酒店,含早餐, 可停车', NULL, '2026-03-24 12:32:36.0400389', NULL);
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('cf9b34dd-ca2a-4922-8206-6a7a1aaf8da3', '江苏省镇江市京口区金山街道长江路215号(西津渡入口处)', NULL, 5.0, NULL, '02bc57f7-78dd-4f66-a11c-7167ae191f0f', '2026-03-24 11:53:51.8206043', '镇江特色菜', '镇江菜馆位于云台山下，紧挨着西津渡古街，交通十分的方便。故名思议，镇江菜馆是一家以经营本地菜肴为主的餐厅。镇江菜馆早餐在当地相当有名，许多本地人都会在早上专程开车到这里吃一顿美味的早餐。', 'Dining', NULL, NULL, NULL, 32.21990554775505, 119.43812297640596, '镇江菜馆(西津渡店)', NULL, NULL, '91', NULL, '镇江香醋排，白果素菜包，西津素什锦，鸡汁干丝，现制豆花，大煮干丝，镇江水晶肴肉，全家福锅盖面，蟹粉狮子头，鲜豆皮，葱香肉包，锅盖面，水晶肴肉，白汁鮰鱼，清炖蟹肉狮子头，镇江醋排，什锦素菜包，清炖狮子头', NULL, '地方菜,午餐, 晚餐, 朋友聚会, 团队聚餐，招牌菜, 老字号', NULL, '2026-03-24 12:36:53.0979693', NULL);
