INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('e52d2767-205a-4d17-9adc-3b0fa3370ce5', '江苏省镇江市京口区姚桥镇儒里村', NULL, 5.0, NULL, 'c43e4778-64dd-483d-b594-7ab869199af8', '2026-04-19 15:44:42.2026041', NULL, '儒里村是著名的“朱子故里”，拥有深厚的儒家文化底蕴和保存完好的明清古建筑群。这里的街巷布局严谨，宗祠文化浓厚，是了解江南宗族社会和拍摄古建筑细节的绝佳去处。', 'BeautifulVillage', NULL, NULL, '非遗文化，乡村摄影', 32.128990142829885, 119.77862837487964, '儒里村', NULL, NULL, NULL, NULL, NULL, NULL, '半日游、拍照打卡、自驾友好、朋友结伴、老人友好、家庭', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('bc76abb8-8d67-404c-9ed4-e1f21dc5460e', '江苏省镇江市丹徒区世业镇世业村', NULL, 5.0, NULL, 'bd011cfd-bda4-4cb0-afb0-588b0bcbed8a', '2026-04-19 15:54:39.2941235', NULL, '位于世业洲旅游度假区核心，世业村是镇江乡村旅游的“金字招牌”。这里环岛公路风景绝美，拥有众多高品质的农家乐和民宿，是品尝江鲜、采摘草莓、周末度假的首选地。', 'BeautifulVillage', NULL, NULL, '乡村美食、乡村休闲', 32.22306040919273, 119.32982811497278, '世业村', NULL, NULL, NULL, NULL, NULL, NULL, '周末短途、夜游、自驾友好、亲子、情侣、家庭', NULL, NULL, '水乡村落');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('db0276fb-e8c7-4652-baad-925007f1ecac', '江苏省镇江市丹徒区辛丰镇黄墟村', NULL, 5.0, NULL, '49f23cfc-b4f9-4ff0-b902-57cc303edebf', '2026-04-19 15:56:30.6448456', NULL, '黄墟村拥有保存完好的民国风情老街，石板路、木结构房屋诉说着往昔的繁华。这里没有喧嚣，只有岁月的沉淀，非常适合拍摄人文纪实照片，感受古镇的静谧。', 'BeautifulVillage', NULL, NULL, '乡村摄影、慢生活', 32.09891050504755, 119.62418423566851, '黄墟村', NULL, NULL, NULL, NULL, NULL, NULL, '半日游、拍照打卡、休闲散步、朋友结伴、老人友好', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('7b39abc2-e7f1-4f82-8911-4a0b7547c29b', '江苏省镇江市丹徒区宝堰镇宝堰村', NULL, 5.0, NULL, '513bc361-1a0c-4c9d-9dca-9ad589d3f2c3', '2026-04-19 16:00:32.2323996', NULL, '宝堰是著名的“美食古镇”，以宝堰干拌面、红烧甲鱼、糯米酒“三绝”闻名。这里的水上老街和古桥见证了运河文化的兴衰，是“吃货”们不可错过的美食打卡地。', 'BeautifulVillage', NULL, NULL, '乡村美食、非遗文化', 31.932125204777652, 119.37252807925353, '宝堰村', NULL, NULL, NULL, NULL, NULL, NULL, '一日游、自驾友好、家庭、朋友结伴', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('463c5735-5234-4868-a1bf-595c2a975856', '江苏省镇江市句容市茅山镇丁庄村', NULL, 5.0, NULL, 'dd13fc3e-590c-4f11-b8b5-e1a309474323', '2026-04-21 07:56:52.5903864', NULL, '作为全国闻名的“葡萄小镇”，丁庄村拥有万亩葡萄园。这里不仅有阳光玫瑰等优质水果采摘，还配套了葡萄博物馆、爱情园等景点，是集吃、住、游、购于一体的成熟乡村旅游目的地。', 'BeautifulVillage', NULL, NULL, '乡村美食、乡村休闲、采摘体验、民宿集群', 31.89872021210199, 119.26495859951964, '丁庄村', NULL, NULL, NULL, NULL, NULL, NULL, '采摘体验、民宿集群、周末短途、自驾友好、亲子农场、亲子、家庭、情侣、中消费', NULL, NULL, '田园乡村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('0e4c1352-b1c9-45c2-977e-3235942289b7', '江苏省镇江市句容市天王镇戴庄村', NULL, 5.0, NULL, '25655e5b-89d9-4c6c-984c-fc8cc1daee8a', '2026-04-21 08:00:27.0978834', NULL, '“赵亚夫精神”的发源地，也是著名的生态农业示范区。戴庄村展示了现代农业与自然和谐共生的图景，有机稻田与果林交织，适合开展研学教育和体验绿色生态生活。', 'BeautifulVillage', NULL, NULL, '乡村休闲、慢生活', 31.648117963505687, 119.24274700764938, '戴庄村', NULL, NULL, NULL, NULL, NULL, NULL, '采摘体验、亲子农场、一日游、自驾友好、亲子、家庭、朋友结伴', NULL, NULL, '田园乡村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('a34a3221-17af-45bc-8f96-201b940b12aa', '江苏省镇江市句容市后白镇西冯村', NULL, 5.0, NULL, '186069ec-c0ed-4ed2-b427-e7ef8bd3cfe1', '2026-04-21 08:03:17.1463026', NULL, '被誉为“中国草坪第一村”，西冯村的田野如同铺开的绿色地毯。这里不仅有壮观的草坪种植基地，还有四季花海，是拍摄田园风光和举办户外草坪婚礼的绝佳之地。', 'BeautifulVillage', NULL, NULL, '乡村摄影、乡村休闲', 31.823164089692806, 119.24587589557117, '西冯村', NULL, NULL, NULL, NULL, NULL, NULL, '乡村集市、拍照打卡、半日游、自驾友好、情侣、朋友结伴', NULL, NULL, '田园乡村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('a0d15acc-7480-4025-b210-6f5390fad9c6', '江苏省镇江市句容市茅山村', NULL, 5.0, NULL, '3f4dbd72-9994-479e-bd1c-9140478d2b7f', '2026-04-21 08:16:40.411164', NULL, '背靠道教圣地茅山，茅山村充满了仙气与灵气。村内保留着南镇街等历史街区，游客可以在此品尝地道的茅山素斋，体验道教文化，或在山脚下的民宿中修身养性。', 'BeautifulVillage', NULL, NULL, '非遗文化、乡村美食', 31.80040432950207, 119.29881034435766, '茅山村', NULL, NULL, NULL, NULL, NULL, NULL, '周末短途、深度游、夜游、老人友好、家庭、朋友结伴、中消费', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('d3c39c01-f50d-4733-89f7-d3e9a301e3cc', '江苏省镇江市句容市衣庄村', NULL, 5.0, NULL, '09e4b7d8-1e27-4e6b-920c-a8e16f5ea0e1', '2026-04-21 08:20:42.0329895', NULL, '衣庄村拥有优美的山水环境和红色历史底蕴。这里的生态农业发达，不仅有优质的果园，还有保存完好的新四军抗战遗迹，适合进行红色教育与生态观光。', 'BeautifulVillage', NULL, NULL, '乡村休闲、乡村摄影', 32.07617534045442, 119.313062051104, '衣庄村', NULL, NULL, NULL, NULL, NULL, NULL, '采摘体验、一日游、自驾友好', NULL, NULL, '生态村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('67fac1da-e19d-48f8-84bd-d3da7ceffde5', '江苏省镇江市扬中市利民村', NULL, 5.0, NULL, 'ea12cc62-9708-4248-a394-1d1e846f655e', '2026-04-21 08:22:21.3948854', NULL, '利民村位于长江之中，拥有典型的江岛湿地景观。这里的“江花湾”风景如画，芦苇荡漾，江风徐徐，是观赏长江落日、体验慢节奏渔家生活的理想之地。', 'BeautifulVillage', NULL, NULL, '慢生活、乡村摄影', 32.109483845228205, 119.89503017404873, '利民村', NULL, NULL, NULL, NULL, NULL, NULL, '一日游、拍照打卡、休闲散步、情侣、朋友结伴、老人友好、低消费', NULL, NULL, '生态村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('8526c1d8-c8fc-411b-83e2-2ff07875d750', '江苏省镇江市扬中市红旗村', NULL, 5.0, NULL, '32ca4d80-67b8-4c4a-b644-a0e9dff03eff', '2026-04-21 08:29:56.70485', NULL, '作为扬中解放的“首登地”，红旗村承载着厚重的红色记忆。游客可以在此追寻渡江战役的足迹，同时体验江岛特有的民俗文化和集市生活。', 'BeautifulVillage', NULL, NULL, '非遗文化、乡村休闲', 32.15160236036039, 119.89061652958655, '红旗村', NULL, NULL, NULL, NULL, NULL, NULL, '半日游、自驾友好、家庭、团建、老人友好、免费', NULL, NULL, '水乡村落');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('385bb516-ede6-4c1a-90db-e33e222ce2fa', '江苏省镇江市扬中市新程村', NULL, 5.0, NULL, '45546db0-6eab-4e30-8cff-71fe3322ec9f', '2026-04-21 08:44:53.0487453', NULL, '新程村拥有广阔的圩田和果园，是体验江岛农业的好去处。这里的共享梨园和生态大米基地非常出名，适合家庭出游，体验亲手采摘的乐趣。', 'BeautifulVillage', NULL, NULL, '乡村休闲、乡村摄影', 32.016680012728294, 119.9174846677289, '新程村', NULL, NULL, NULL, NULL, NULL, NULL, '采摘体验、一日游、亲子农场、自驾友好、亲子、家庭、中消费', NULL, NULL, '田园乡村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('a25f6e7d-7082-4815-bfde-12ded63eb800', '江苏省镇江市扬中市鸣凤村', NULL, 5.0, NULL, '5d3fcba8-125e-4d0b-bc93-e978b275df82', '2026-04-21 08:59:28.4443224', NULL, '鸣凤村保留了传统的江岛民居风貌，方家埭等地古色古香。这里生活气息浓厚，适合漫步村头巷尾，感受原汁原味的扬中乡村风情。', 'BeautifulVillage', NULL, NULL, '慢生活、乡村摄影', 32.14171757816256, 119.81577330771724, '鸣凤村', NULL, NULL, NULL, NULL, NULL, NULL, '半日游、休闲散步、老人友好、朋友结伴', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('049f7f1c-b97c-433c-9e3b-3b26fc792f27', '江苏省镇江市京口区华山村', NULL, 5.0, NULL, '06383ddd-1061-4a31-83d5-5ff43b4e3b58', '2026-04-21 09:09:33.3216218', NULL, '背靠圌山，面朝长江，华山村地理位置得天独厚。村内的华山古庙历史悠久，每年庙会热闹非凡。这里适合登山祈福，俯瞰长江壮阔景色，体验山脚下的宁静村落生活。', 'BeautifulVillage', NULL, NULL, '乡村休闲、乡村摄影', 32.13918389875706, 119.7330779973852, '华山村', NULL, NULL, NULL, NULL, NULL, NULL, '一日游、拍照打卡、自驾友好、朋友结伴、家庭、低消费', NULL, NULL, '历史古村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('8489d55f-ada8-427f-a653-3c952b2a1d40', '江苏省镇江市润州区️ 五洲山村', NULL, 5.0, NULL, '68097227-201e-4e23-b2fe-2d36695d17a7', '2026-04-21 09:18:17.7763738', NULL, '五洲山村是一个“城在村中、村在景中”的独特乡村，既有城市文明的便利，又保留了浓郁的田园乡愁。这里不仅是全国文明村，更是茶产业特色村，连绵的茶山构成了其最亮丽的风景线。游客可以漫步在朱家湾生态公园，探访记录着百年家族历史的村史馆，感受深厚的文化底蕴。', 'BeautifulVillage', NULL, NULL, '乡村休闲、乡村美食、非遗文化、慢生活', 32.17526912973569, 119.3962705633739, '五洲山村', NULL, NULL, NULL, NULL, NULL, NULL, '采摘体验、亲子农场、周末短途、一日游、自驾友好、拍照打卡、亲子、家庭、朋友结伴、低消费、中消费', NULL, '2026-04-21 12:22:18.2771488', '田园乡村');
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('9743430e-5f0e-445b-a1f7-05c82b102c06', '江苏省镇江市润州区嶂山村', NULL, 5.0, NULL, '4e8a84c1-e247-45f4-87da-0eaca41d1a1e', '2026-04-21 09:26:44.7836896', NULL, '坐落于十里长山脚下的嶂山村，是一个将“美丽风景”成功转化为“美丽经济”的典范。这里不仅是江苏省“最美乡村”，更以其独特的“甜蜜产业”闻名。春季，450余亩桃花竞相绽放，村庄会举办盛大的“桃醉嶂山”桃花季，游客可以参与汉服巡游、在特色市集品尝桃花特调，或认领一棵爱心桃树，体验“春赏花、夏采果”的完整乐趣。', 'BeautifulVillage', NULL, NULL, '乡村休闲、乡村美食、非遗文化、慢生活', 32.1640599961563, 119.41440869907862, '嶂山村', NULL, NULL, NULL, NULL, NULL, NULL, '周末短途、一日游、自驾友好、拍照打卡、亲子、家庭、朋友结伴、低消费、中消费', NULL, NULL, '田园乡村');
