INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('312bed5e-a963-4f3c-8b39-789dcb980d41', '江苏省镇江市京口区华山古寺', NULL, 5.0, NULL, '7eb76f3a-4b60-4b57-8eba-9fb7378a6600', '2026-04-21 11:56:38.3588855', NULL, '华山古寺原名张王庙，始建于南朝梁时期（502-557年），为纪念夏禹时期治水英雄张勃而建。该寺历经多次毁坏与重建，现存建筑为后期修复，由妙能法师主持发展为村中寺庙。寺前遗存1520年树龄的千年银杏（2023年树高33.8米），寺内供奉因中毒传说呈黑色面容的张大帝塑像，寺前保留千年历史的皇家等级无字碑。', 'Attraction', NULL, NULL, NULL, 32.138950996639586, 119.73318489574088, '华山古寺', '全天24小时放', NULL, NULL, NULL, NULL, NULL, '古迹、寺庙,village:26b3b83d-aa48-4472-85c2-5c88c0bcd9da', '免费', NULL, NULL);
INSERT INTO [Resources] ([Id], [Address], [Amenities], [AverageRating], [BestVisitTime], [CoverMediaId], [CreatedAt], [CuisineType], [Description], [Discriminator], [Duration], [EventDate], [FamousFor], [Latitude], [Longitude], [Name], [OpeningHours], [Organizer], [PriceRange], [RoomTypes], [SignatureDishes], [StarRating], [Tags], [TicketPrice], [UpdatedAt], [VillageType]) VALUES ('0e9b6d1c-d37c-48d5-9e09-297787ec84f6', '江苏省镇江市京口区华山村', NULL, 5.0, NULL, '1cae6aef-2520-47c3-9431-bcd6a48ef07a', '2026-04-21 12:08:04.1716204', NULL, '华山古寺原名张王庙，始建于南朝梁时期（502-557年），为纪念夏禹时期治水英雄张勃而建。该寺历经多次毁坏与重建，现存建筑为后期修复，由妙能法师主持发展为村中寺庙。寺前遗存1520年树龄的千年银杏（2023年树高33.8米），寺内供奉因中毒传说呈黑色面容的张大帝塑像，寺前保留千年历史的皇家等级无字碑。', 'Attraction', NULL, NULL, NULL, 32.13918389875706, 119.7330779973852, '华山古寺', '08:00 - 17:00', NULL, NULL, NULL, NULL, NULL, '古迹,village:26b3b83d-aa48-4472-85c2-5c88c0bcd9da', '免费', '2026-04-21 12:08:40.5919892', NULL);
